def token_case(s, exceptions=['URL', 'ID']):
    tokens = s.split('_')
    camel_case_tokens = [tokens[0].lower()]

    for token in tokens[1:]:
        if token in exceptions:
            camel_case_tokens.append(token)
        else:
            camel_case_tokens.append(token.capitalize())

    return ''.join(camel_case_tokens)

# Edge case: Single word without an underscore
assert token_case('singleword') == 'singleword', "Single word without underscore should remain unchanged"
